import { memo } from 'react'
import './ProductCard.css'

const ProductCard = memo(({ product }) => {
  const { id, title, price, category } = product ?? {}

  return (
    <article className="product-card">
      <div className="product-card__image">
        <div className="product-card__placeholder" />
        <span className="product-card__badge">{category}</span>
      </div>
      <div className="product-card__body">
        <h3 className="product-card__title">{title || 'Product Title'}</h3>
        <p className="product-card__price">${typeof price === 'number' ? price.toFixed(2) : price ?? '0.00'}</p>
        <button type="button" className="product-card__btn">Add to Cart</button>
      </div>
    </article>
  )
})

ProductCard.displayName = 'ProductCard'

export default ProductCard
